parameters.text:
=You are an expert in electronic waste (e-waste) material analysis.

Analyse the uploaded e-waste image and return ONLY valid JSON (no markdown, no backticks) with this exact structure:
{
  "image_name": "{{ $('Webhook — Receive Image').item.json.body.original_name }}",
  "metals_detected": [
    { "name": "Copper", "symbol": "Cu", "recoverable": true, "estimated_weight_g": 45, "percentage": 18 }
  ],
  "total_recoverable_percentage": 72,
  "negative_impacts": [
    "Toxic fumes during smelting",
    "Acid leaching contaminates groundwater"
  ],
  "summary": "Brief 2-sentence summary of the device and its composition."
}

parameters.jsCode:
const raw = $input.item.json.output || $input.item.json.text || '';
let analysis;
try {
  // Strip accidental markdown fences
  const cleaned = raw.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { error: 'Parse failed', raw };
}
return [{ json: { analysis, original_name: $('Webhook — Receive Image').item.json.body.original_name } }];

const analysis   = $('Parse AI Response').item.json.analysis;
const imgName    = $('Parse AI Response').item.json.original_name || 'image';
const marketData = $input.item.json;  // from Flask /metal-prices

// Build metals rows
const metalsRows = (analysis.metals_detected || []).map(m => `
  <tr>
    <td>${m.name} (${m.symbol})</td>
    <td>${m.recoverable ? '<span class="badge green">Yes</span>' : '<span class="badge red">No</span>'}</td>
    <td>${m.estimated_weight_g ?? '—'} g</td>
    <td>${m.percentage ?? '—'}%</td>
  </tr>`).join('');

// Build impacts list
const impacts = (analysis.negative_impacts || []).map(i => `<li>${i}</li>`).join('');

// Build chart data arrays
const metals     = (analysis.metals_detected || []).map(m => m.name);
const pcts       = (analysis.metals_detected || []).map(m => m.percentage || 0);
const weights    = (analysis.metals_detected || []).map(m => m.estimated_weight_g || 0);

// Market price data from Flask (expected: { prices: { Metal: [{date,price},...] } })
const pricesRaw  = (marketData && marketData.prices) ? marketData.prices : {};

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0" />
<title>E-Waste Report — ${imgName}</title>
<script src="https://cdn.plot.ly/plotly-2.30.0.min.js"><\/script>
<style>
  :root {
    --bg: #0f1117; --card: #1a1d2e; --border: #2a2d3e;
    --accent: #6c63ff; --green: #66bb6a; --red: #ef5350;
    --text: #e0e0e0; --muted: #8b8fa8;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Segoe UI', sans-serif; background: var(--bg); color: var(--text); padding: 32px; }
  h1 { font-size: 26px; margin-bottom: 6px; }
  .subtitle { color: var(--muted); font-size: 14px; margin-bottom: 28px; }
  .grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 24px; }
  .card { background: var(--card); border: 1px solid var(--border); border-radius: 12px; padding: 24px; }
  .card h2 { font-size: 15px; color: var(--accent); margin-bottom: 14px; text-transform: uppercase; letter-spacing: .5px; }
  .img-wrap { text-align: center; }
  .img-wrap img { max-width: 100%; border-radius: 8px; max-height: 320px; object-fit: contain; }
  .img-name { margin-top: 10px; font-size: 13px; color: var(--muted); }
  table { width: 100%; border-collapse: collapse; font-size: 13px; }
  th { text-align: left; padding: 8px 10px; border-bottom: 1px solid var(--border); color: var(--muted); font-weight: 600; }
  td { padding: 8px 10px; border-bottom: 1px solid #1e2035; }
  .badge { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 11px; font-weight: 700; }
  .badge.green { background: #1b3a2e; color: var(--green); }
  .badge.red   { background: #3a1e1e; color: var(--red);   }
  .stat-box { display: flex; align-items: center; gap: 12px; padding: 14px; background: #12141f; border-radius: 8px; margin-bottom: 10px; }
  .stat-num { font-size: 28px; font-weight: 700; color: var(--accent); }
  .stat-label { font-size: 12px; color: var(--muted); margin-top: 2px; }
  ul.impacts { list-style: none; }
  ul.impacts li { padding: 7px 0; border-bottom: 1px solid #1e2035; font-size: 13px; }
  ul.impacts li::before { content: '⚠ '; color: #ffb74d; }
  .summary-box { font-size: 14px; line-height: 1.7; color: #c0c3d8; }
  #chart-market, #chart-pie, #chart-bar { width: 100%; height: 380px; }
  .full { grid-column: 1 / -1; }
  .date-picker { display: flex; gap: 10px; align-items: center; margin-bottom: 12px; flex-wrap: wrap; }
  .date-picker label { font-size: 12px; color: var(--muted); }
  .date-picker input { background: #12141f; border: 1px solid var(--border); color: var(--text); padding: 5px 10px; border-radius: 6px; font-size: 12px; }
  .date-picker button { background: var(--accent); border: none; color: #fff; padding: 5px 14px; border-radius: 6px; cursor: pointer; font-size: 12px; }
<\/style>
</head>
<body>

<h1>&#9851; E-Waste Analysis Report</h1>
<div class="subtitle">Generated: ${new Date().toLocaleString()}</div>

<div class="grid">

  <!-- Image -->
  <div class="card img-wrap">
    <h2>Input Image</h2>
    <img src="data:image/png;base64,PLACEHOLDER_BASE64" alt="${imgName}" />
    <div class="img-name">${imgName}</div>
  </div>

  <!-- Summary -->
  <div class="card">
    <h2>Summary</h2>
    <div class="summary-box">${analysis.summary || 'No summary available.'}</div>
    <br/>
    <div class="stat-box">
      <div class="stat-num">${analysis.total_recoverable_percentage ?? 0}%</div>
      <div><div style="font-size:14px">Total Recoverable Material</div><div class="stat-label">by weight estimation</div></div>
    </div>
  </div>

  <!-- Metals Table -->
  <div class="card">
    <h2>Metals Detected</h2>
    <table>
      <thead><tr><th>Metal</th><th>Recoverable</th><th>Est. Weight</th><th>% Share</th></tr></thead>
      <tbody>${metalsRows}</tbody>
    </table>
  </div>

  <!-- Negative Impacts -->
  <div class="card">
    <h2>Environmental / Health Impacts</h2>
    <ul class="impacts">${impacts}</ul>
  </div>

  <!-- Pie Chart -->
  <div class="card">
    <h2>Material Composition (%)</h2>
    <div id="chart-pie"></div>
  </div>

  <!-- Bar Chart -->
  <div class="card">
    <h2>Estimated Weight by Metal (g)</h2>
    <div id="chart-bar"></div>
  </div>

  <!-- Market Price Chart (full width) -->
  <div class="card full">
    <h2>Metal Market Prices — Last 12 Months (USD/kg)</h2>
    <div class="date-picker">
      <label>From: <input type="date" id="date-from" /></label>
      <label>To: <input type="date" id="date-to" /></label>
      <button onclick="filterChart()">Apply</button>
      <button onclick="resetChart()">Reset</button>
    </div>
    <div id="chart-market"></div>
  </div>

</div>

<script>
/* ── Static charts ─────────────────────────────────────────────────────── */
const metals  = ${JSON.stringify(metals)};
const pcts    = ${JSON.stringify(pcts)};
const weights = ${JSON.stringify(weights)};

const COLORS = ['#6c63ff','#4facfe','#66bb6a','#ffb74d','#ef5350','#ab47bc','#26c6da','#ff7043'];

Plotly.newPlot('chart-pie', [{
  type:'pie', labels:metals, values:pcts,
  marker:{ colors:COLORS },
  textinfo:'label+percent',
  hole: 0.4,
  textfont:{ color:'#e0e0e0' }
}], {
  paper_bgcolor:'transparent', plot_bgcolor:'transparent',
  font:{ color:'#e0e0e0' }, margin:{ t:10,b:10,l:10,r:10 },
  showlegend: false
}, { responsive:true, displayModeBar:false });

Plotly.newPlot('chart-bar', [{
  type:'bar', x:metals, y:weights,
  marker:{ color:COLORS }, text:weights.map(w=>w+'g'), textposition:'outside'
}], {
  paper_bgcolor:'transparent', plot_bgcolor:'#12141f',
  font:{ color:'#e0e0e0' }, margin:{ t:10,b:40,l:40,r:10 },
  xaxis:{ gridcolor:'#2a2d3e' }, yaxis:{ gridcolor:'#2a2d3e', title:'grams' }
}, { responsive:true, displayModeBar:false });

/* ── Market chart with zoom + date filter ─────────────────────────────── */
const pricesRaw = ${JSON.stringify(pricesRaw)};
let allTraces = [];
let minDate = '', maxDate = '';

Object.entries(pricesRaw).forEach(([metal, pts], idx) => {
  if (!Array.isArray(pts)) return;
  const dates  = pts.map(p => p.date);
  const prices = pts.map(p => p.price);
  if (!minDate || dates[0] < minDate) minDate = dates[0];
  if (!maxDate || dates[dates.length-1] > maxDate) maxDate = dates[dates.length-1];
  allTraces.push({
    type:'scatter', mode:'lines', name:metal,
    x:dates, y:prices, line:{ color:COLORS[idx % COLORS.length], width:2 }
  });
});

const marketLayout = {
  paper_bgcolor:'transparent', plot_bgcolor:'#12141f',
  font:{ color:'#e0e0e0' }, margin:{ t:10,b:40,l:60,r:10 },
  xaxis:{ gridcolor:'#2a2d3e', rangeslider:{} },
  yaxis:{ gridcolor:'#2a2d3e', title:'USD / kg' },
  legend:{ bgcolor:'#1a1d2e', bordercolor:'#2a2d3e', borderwidth:1 },
  hovermode:'x unified'
};

Plotly.newPlot('chart-market', allTraces, marketLayout, { responsive:true });

if (minDate) document.getElementById('date-from').value = minDate;
if (maxDate) document.getElementById('date-to').value   = maxDate;

function filterChart() {
  const from = document.getElementById('date-from').value;
  const to   = document.getElementById('date-to').value;
  Plotly.relayout('chart-market', { 'xaxis.range': [from, to] });
}
function resetChart() {
  Plotly.relayout('chart-market', { 'xaxis.autorange': true });
}
<\/script>
</body>
</html>`;

return [{ json: { html, image_name: imgName } }];
